import edu.ucr.cs.bdlab.beast.geolite.EnvelopeNDLite
import edu.ucr.cs.bdlab.beast.generator.SpatialGeneratorBuilder

val minX = 1.0
val minY = 2.0
val maxX = 5.0
val maxY = 6.0
val desiredMBR = new EnvelopeNDLite(2, minX, minY, maxX, maxY)

val numRecords = 100

// Initialize the builder, set the MBR, and generate the spatial RDD
val generatedData = new SpatialGeneratorBuilder(sc)
  .mbr(desiredMBR)
  .uniform(numRecords)

// Force materialization and verify the count
val count = generatedData.count()
assert(count == numRecords, s"Expected $numRecords records, but got $count")

// Verify that all generated features fall within the specified MBR
val outOfBounds = generatedData.filter { feature =>
  val geom = feature.getGeometry
  if (geom == null) {
    false
  } else {
    val env = geom.getEnvelopeInternal
    // Check if the geometry's envelope exceeds the specified MBR bounds
    env.getMinX < minX || env.getMinY < minY || env.getMaxX > maxX || env.getMaxY > maxY
  }
}.count()

assert(outOfBounds == 0, s"Found $outOfBounds features outside the specified MBR bounds [$minX, $minY, $maxX, $maxY]")

println(s"__CHECK__ mbr $count")

