import edu.ucr.cs.bdlab.raptor._
import org.apache.spark.rdd.RDD

// 1. Define the spatial metadata grid (360x180 total size, 90x90 tile size)
val metadata = RasterMetadata.create(-180.0, 90.0, 180.0, -90.0, 4326, 360, 180, 90, 90)

// 2. Define the raster feature attributes (e.g., target filename)
val feature = RasterFeature.create(Array("fileName"), Array("output.tif"))

// 3. Create an RDD of sparse pixel coordinates and values
// These 3 pixels fall into 3 distinct 90x90 tiles:
// (0, 0) -> Tile (0, 0)
// (180, 0) -> Tile (2, 0)
// (100, 50) -> Tile (1, 0)
val pixels: RDD[(Int, Int, Float)] = sc.parallelize(Seq(
  (0, 0, 100f),
  (180, 0, 200f),
  (100, 50, 300f)
))

// 4. Rasterize the pixels into a RasterRDD
val rasterized: RasterRDD[Float] = RasterOperationsGlobal.rasterizePixels[Float](pixels, metadata, feature)

// 5. Force materialization and verify the result
val count = rasterized.count()

// Since the pixels fall into exactly 3 distinct tiles, the resulting RDD should contain exactly 3 tiles
assert(count == 3, s"Expected exactly 3 tiles to be created for the 3 sparse pixels, but got $count")
println(s"__CHECK__ rasterizePixels $count")

