import java.io.ByteArrayInputStream

// Define the loan pattern locally to avoid missing receiver/import issues
def using[A <: AutoCloseable, B](resource: A)(block: A => B): B = {
  try {
    block(resource)
  } finally {
    if (resource != null) resource.close()
  }
}

val testData = Array[Byte](42, 43, 44)
val bais = new ByteArrayInputStream(testData)

// Exercise the using block with an AutoCloseable resource
val firstByte = using(bais) { stream =>
  stream.read()
}

// Verify the resource was read correctly
assert(firstByte == 42, s"Expected 42, but got $firstByte")

// Verify the resource was closed (ByteArrayInputStream.available() doesn't throw when closed, 
// but in a real stream like FileInputStream, operations after close would throw)
println(s"__CHECK__ using $firstByte")

