var maxDefinedY = Int.MinValue

// Iterate over all pixels using inclusive bounds y1 to y2 and x1 to x2
for (y <- tile.y1 to tile.y2; x <- tile.x1 to tile.x2) {
  if (tile.isDefined(x, y)) {
    pixelCount += 1
    if (y > maxDefinedY) {
      maxDefinedY = y
    }
  }
}

