val expectedMaxPixels = (tile.x2 - tile.x1 + 1) * (tile.y2 - tile.y1 + 1)
assert(pixelCount <= expectedMaxPixels, s"Pixel count $pixelCount exceeds bounding box size $expectedMaxPixels")

